// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Exchange a magic-link token for a portal token pair
	// (POST /api/auth/magic-link/exchange)
	ExchangeMagicLink(ctx context.Context, request ExchangeMagicLinkRequestObject) (ExchangeMagicLinkResponseObject, error)
	// Request a magic-link sign-in email
	// (POST /api/auth/magic-link/request)
	RequestMagicLink(ctx context.Context, request RequestMagicLinkRequestObject) (RequestMagicLinkResponseObject, error)
	// Exchange OAuth authorization code for a portal token pair
	// (POST /api/auth/oauth/callback)
	OauthCallback(ctx context.Context, request OauthCallbackRequestObject) (OauthCallbackResponseObject, error)
	// Begin OAuth authorization flow — returns the provider authorize URL
	// (POST /api/auth/oauth/start)
	StartOAuth(ctx context.Context, request StartOAuthRequestObject) (StartOAuthResponseObject, error)
	// Exchange a refresh token for a new access+refresh pair
	// (POST /api/auth/refresh)
	RefreshToken(ctx context.Context, request RefreshTokenRequestObject) (RefreshTokenResponseObject, error)
	// Revoke a token (or all tokens for the account)
	// (POST /api/auth/revoke)
	RevokeToken(ctx context.Context, request RevokeTokenRequestObject) (RevokeTokenResponseObject, error)
	// Return the authenticated account's profile and org memberships
	// (GET /api/me)
	GetMe(ctx context.Context, request GetMeRequestObject) (GetMeResponseObject, error)
	// Create a new org; the authenticated account becomes its creator
	// (POST /api/orgs)
	CreateOrg(ctx context.Context, request CreateOrgRequestObject) (CreateOrgResponseObject, error)
	// Create an org invite (requires creator role); sends email to recipient
	// (POST /api/orgs/{orgID}/invites)
	CreateOrgInvite(ctx context.Context, request CreateOrgInviteRequestObject) (CreateOrgInviteResponseObject, error)
	// Accept a pending org invite (requires Bearer; verifies token + recipient email)
	// (POST /api/orgs/{orgID}/invites/{inviteID}/accept)
	AcceptOrgInvite(ctx context.Context, request AcceptOrgInviteRequestObject) (AcceptOrgInviteResponseObject, error)
	// List members of an org (requires creator or member role)
	// (GET /api/orgs/{orgID}/members)
	ListOrgMembers(ctx context.Context, request ListOrgMembersRequestObject) (ListOrgMembersResponseObject, error)
	// List sessions visible to the caller (active + recent), cursor-paginated
	// (GET /api/orgs/{orgID}/sessions)
	ListSessions(ctx context.Context, request ListSessionsRequestObject) (ListSessionsResponseObject, error)
	// Create a new session in the org; the authenticated account becomes the creator
	// (POST /api/orgs/{orgID}/sessions)
	CreateSession(ctx context.Context, request CreateSessionRequestObject) (CreateSessionResponseObject, error)
	// Get a session's metadata and member list
	// (GET /api/orgs/{orgID}/sessions/{sessionID})
	GetSession(ctx context.Context, request GetSessionRequestObject) (GetSessionResponseObject, error)
	// Update goal, scope (widening only), or default_mode; creator only
	// (PATCH /api/orgs/{orgID}/sessions/{sessionID})
	PatchSession(ctx context.Context, request PatchSessionRequestObject) (PatchSessionResponseObject, error)
	// Abandon the session without finalizing; sets status=ended, end_reason=abandoned; creator only
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/abandon)
	AbandonSession(ctx context.Context, request AbandonSessionRequestObject) (AbandonSessionResponseObject, error)
	// List comments in a session, cursor-paginated, with optional filters
	// (GET /api/orgs/{orgID}/sessions/{sessionID}/comments)
	ListComments(ctx context.Context, request ListCommentsRequestObject) (ListCommentsResponseObject, error)
	// Mark a comment as resolved with an optional resolution note
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/comments/{commentId}/resolve)
	ResolveComment(ctx context.Context, request ResolveCommentRequestObject) (ResolveCommentResponseObject, error)
	// Assembled turn-start digest for additionalContext injection
	// (GET /api/orgs/{orgID}/sessions/{sessionID}/digest)
	GetSessionDigest(ctx context.Context, request GetSessionDigestRequestObject) (GetSessionDigestResponseObject, error)
	// Transition session to finalizing; idempotent if already finalizing
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/finalize)
	FinalizeSession(ctx context.Context, request FinalizeSessionRequestObject) (FinalizeSessionResponseObject, error)
	// Invite a user to a session by email; sends a magic-link-style join email
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/invites)
	InviteToSession(ctx context.Context, request InviteToSessionRequestObject) (InviteToSessionResponseObject, error)
	// Accept a session invite; binds the caller to the session as a member
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/invites/{inviteID}/accept)
	AcceptSessionInvite(ctx context.Context, request AcceptSessionInviteRequestObject) (AcceptSessionInviteResponseObject, error)
	// Remove a member from a session; creator only
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/members/{accountID}/remove)
	RemoveSessionMember(ctx context.Context, request RemoveSessionMemberRequestObject) (RemoveSessionMemberResponseObject, error)
	// List all refs in the session bare repository with mode and tip SHA
	// (GET /api/orgs/{orgID}/sessions/{sessionID}/refs)
	ListSessionRefs(ctx context.Context, request ListSessionRefsRequestObject) (ListSessionRefsResponseObject, error)
}

type StrictHandlerFunc func(ctx context.Context, w http.ResponseWriter, r *http.Request, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

